import{_ as a,o as s,c as i,ai as t}from"./chunks/framework.C4ntERNc.js";const m=JSON.parse('{"title":"Templates","description":"","frontmatter":{"title":"Templates","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/formal-reference/templates.md","filePath":"reference-manual/formal-reference/templates.md"}'),l={name:"reference-manual/formal-reference/templates.md"};function n(o,e,r,p,c,d){return s(),i("div",null,[...e[0]||(e[0]=[t(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/formal-reference/templates.md for this page in Markdown format</div><h1 id="templates-template-apply" tabindex="-1">Templates (<code>@template</code> / <code>@apply</code>) <a class="header-anchor" href="#templates-template-apply" aria-label="Permalink to “Templates (@template / @apply)”">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to “Purpose”">​</a></h2><p>Templates provide <strong>compile-time reusable logic blocks</strong> that expand inline into statements without introducing new hardware structure. Templates do <strong>not</strong> create modules, ports, wires, registers, memories, or storage of any kind. They exist solely to reduce code duplication while preserving the structural determinism of JZ-HDL.</p><p>Templates expand before semantic analysis. The expanded code must independently satisfy all JZ-HDL rules (Exclusive Assignment, driver determinism, width rules).</p><p>Templates are strictly limited to prevent them from becoming &quot;mini-modules.&quot;</p><h2 id="template-definition" tabindex="-1">Template Definition <a class="header-anchor" href="#template-definition" aria-label="Permalink to “Template Definition”">​</a></h2><p><strong>Syntax:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@template &lt;template_id&gt; (&lt;param_0&gt;, &lt;param_1&gt;, ..., &lt;param_n&gt;)</span></span>
<span class="line"><span>  &lt;template_body&gt;</span></span>
<span class="line"><span>@endtemplate</span></span></code></pre></div><p><strong>Placement:</strong></p><ul><li><strong>Module-scoped:</strong> Inside a <code>@module</code> block, alongside other declaration blocks (CONST, PORT, WIRE, etc.), but outside any <code>ASYNCHRONOUS</code> or <code>SYNCHRONOUS</code> body. Module-scoped templates are visible only within that module.</li><li><strong>File-scoped:</strong> At file scope, outside any <code>@module</code> or <code>@project</code>, similar to <code>@global</code>. File-scoped templates are visible to all modules in the compilation unit.</li></ul><p><strong>Rules:</strong></p><ul><li><code>&lt;template_id&gt;</code> follows identifier rules.</li><li>Parameter list may contain zero or more identifiers.</li><li>Parameters are placeholders for identifiers or expressions at the callsite.</li><li>Template bodies do <strong>not</strong> create a new namespace; after expansion the statements belong to the enclosing scope.</li></ul><h2 id="allowed-content" tabindex="-1">Allowed Content <a class="header-anchor" href="#allowed-content" aria-label="Permalink to “Allowed Content”">​</a></h2><p>A template may contain only:</p><h3 id="statements" tabindex="-1">Statements <a class="header-anchor" href="#statements" aria-label="Permalink to “Statements”">​</a></h3><ul><li>Directional assignments: <code>&lt;=</code>, <code>=&gt;</code>, <code>&lt;=z</code>, <code>&lt;=s</code>, <code>=&gt;z</code>, <code>=&gt;s</code></li><li>Alias assignments: <code>=</code>, <code>=z</code>, <code>=s</code> (subject to the same alias rules as outside templates — no aliases in SYNCHRONOUS blocks, no aliases in conditionals, no literal RHS)</li><li>All identifiers on either side of an assignment must be template parameters or scratch wires. A template may not reference identifiers outside its parameter list; all external signals must be passed in as arguments.</li><li><strong>Exception:</strong> Compile-time constants (<code>CONST</code>, <code>CONFIG</code>) and <code>@global</code> values (e.g., <code>CMD.READ</code>) may appear in expressions without being passed as parameters.</li><li>Conditional logic: <code>IF</code> / <code>ELIF</code> / <code>ELSE</code>, <code>SELECT</code> / <code>CASE</code></li></ul><h3 id="expressions" tabindex="-1">Expressions <a class="header-anchor" href="#expressions" aria-label="Permalink to “Expressions”">​</a></h3><ul><li>Any valid JZ-HDL expression.</li><li>Template parameters may appear in expressions, slice indices, and concatenations.</li></ul><h3 id="scratch-wires" tabindex="-1">Scratch Wires <a class="header-anchor" href="#scratch-wires" aria-label="Permalink to “Scratch Wires”">​</a></h3><p>Defined via a restricted syntax:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@scratch &lt;scratch_id&gt; [&lt;width&gt;];</span></span></code></pre></div><p><strong>Scratch rules:</strong></p><ul><li>Scratch wires exist only inside a single expansion site.</li><li>They cannot be referenced outside the template.</li><li>They are implicitly allocated as internal, anonymous nets.</li><li>They may participate in <code>&lt;=</code>, <code>=&gt;</code>, and <code>=</code> assignments.</li><li>They do not appear in module namespace.</li><li>They may not shadow any existing identifier.</li><li>Width expressions must be a compile-time constant expression after parameter and IDX substitution. Compile-time intrinsics such as <code>widthof()</code> and <code>clog2()</code> may be used (e.g., <code>@scratch sum [widthof(a)+1]</code>).</li></ul><p><strong>Usage example:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@scratch tmp [8];</span></span>
<span class="line"><span>tmp &lt;= a + b;</span></span>
<span class="line"><span>out &lt;= tmp;</span></span></code></pre></div><h2 id="forbidden-content" tabindex="-1">Forbidden Content <a class="header-anchor" href="#forbidden-content" aria-label="Permalink to “Forbidden Content”">​</a></h2><p>Templates may <strong>not</strong> contain:</p><h3 id="declarations" tabindex="-1">Declarations <a class="header-anchor" href="#declarations" aria-label="Permalink to “Declarations”">​</a></h3><ul><li><code>WIRE</code>, <code>REGISTER</code>, <code>PORT</code>, <code>CONST</code>, <code>MEM</code>, <code>MUX</code></li><li><code>@new</code>, <code>@module</code>, <code>@project</code></li><li><code>CDC</code></li><li><code>SYNCHRONOUS</code> or <code>ASYNCHRONOUS</code> block headers</li></ul><h3 id="other-restrictions" tabindex="-1">Other Restrictions <a class="header-anchor" href="#other-restrictions" aria-label="Permalink to “Other Restrictions”">​</a></h3><ul><li>No nested <code>@template</code> definitions</li><li>No clock or reset logic</li><li>No <code>@feature</code> blocks</li><li>Template parameters cannot represent widths; they represent <em>identifiers</em> or <em>expressions</em> only</li><li>Scratch wires cannot be sliced outside the template</li></ul><h2 id="template-application-apply" tabindex="-1">Template Application (<code>@apply</code>) <a class="header-anchor" href="#template-application-apply" aria-label="Permalink to “Template Application (@apply)”">​</a></h2><p><strong>Syntax:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@apply &lt;template_id&gt; (&lt;arg_0&gt;, &lt;arg_1&gt;, ..., &lt;arg_n&gt;);</span></span>
<span class="line"><span>@apply [count] &lt;template_id&gt; (&lt;arg_0&gt;, &lt;arg_1&gt;, ..., &lt;arg_n&gt;);</span></span></code></pre></div><p><strong>Rules:</strong></p><ul><li>Present only inside <code>ASYNCHRONOUS</code> or <code>SYNCHRONOUS</code> bodies.</li><li>Argument count must match the template&#39;s parameter count.</li><li><code>&lt;count&gt;</code> is the number of times to apply the template: <ul><li>Must be a compile-time nonnegative integer constant; if omitted it defaults to <code>1</code>.</li><li>If <code>count == 1</code>, the template is expanded once and <code>IDX</code> is implicitly bound to <code>0</code>.</li><li>If <code>count &gt; 1</code>, the template is expanded <code>count</code> times; in expansion k (0 &lt;= k &lt; count) <code>IDX</code> is substituted with the integer literal <code>k</code>.</li><li>If <code>count == 0</code>, the apply is a no-op.</li></ul></li></ul><h3 id="idx-rules" tabindex="-1">IDX Rules <a class="header-anchor" href="#idx-rules" aria-label="Permalink to “IDX Rules”">​</a></h3><ul><li><code>IDX</code> is a compile-time integer literal available inside the template after substitution.</li><li><code>IDX</code> is <strong>not</strong> a runtime signal and may be used <strong>only</strong> in compile-time contexts: <ul><li>Slice bounds</li><li>Instance naming</li><li><code>OVERRIDE</code> expressions</li><li>CONST initializers</li><li>Array/instance indices</li></ul></li><li>Using <code>IDX</code> in a runtime expression (e.g., as a value assigned to a register or as a combinational operand) is a compile-time error.</li></ul><h3 id="arguments" tabindex="-1">Arguments <a class="header-anchor" href="#arguments" aria-label="Permalink to “Arguments”">​</a></h3><p>Each <code>&lt;arg_i&gt;</code> must be:</p><ul><li>An identifier</li><li>A slice (slice indices may include <code>IDX</code> since it is compile-time substituted)</li><li>A valid JZ-HDL expression (subject to <code>IDX</code> rules)</li><li>A port/reference (<code>inst.port</code>)</li></ul><h3 id="post-expansion-validation" tabindex="-1">Post-expansion Validation <a class="header-anchor" href="#post-expansion-validation" aria-label="Permalink to “Post-expansion Validation”">​</a></h3><p>After expansion the generated code is validated by the normal semantic checks (Exclusive Assignment, widths, name uniqueness). If expansion produces duplicate identifiers, the template author must include <code>IDX</code> in names to ensure uniqueness.</p><h3 id="expansion-semantics" tabindex="-1">Expansion Semantics <a class="header-anchor" href="#expansion-semantics" aria-label="Permalink to “Expansion Semantics”">​</a></h3><ul><li>The template is expanded <strong>inline</strong> at the callsite.</li><li>Parameters are replaced with their provided arguments via capture-avoiding substitution.</li><li>Scratch wires become compiler-generated nets unique per callsite.</li><li>After expansion, the resulting statements undergo full semantic analysis.</li></ul><h2 id="exclusive-assignment-compatibility" tabindex="-1">Exclusive Assignment Compatibility <a class="header-anchor" href="#exclusive-assignment-compatibility" aria-label="Permalink to “Exclusive Assignment Compatibility”">​</a></h2><p>Template expansion does <strong>not</strong> bypass or weaken the Exclusive Assignment Rule.</p><p>After expansion:</p><ul><li>Every assignment in the template behaves exactly as if written by the author at the callsite.</li><li>Multiple <code>@apply</code> calls that assign the same identifier must still be exclusive by structure or path.</li><li>Violations inside expanded templates produce normal assignment-conflict errors.</li></ul><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to “Examples”">​</a></h2><h3 id="simple-arithmetic-pattern-saturating-add" tabindex="-1">Simple arithmetic pattern (saturating add) <a class="header-anchor" href="#simple-arithmetic-pattern-saturating-add" aria-label="Permalink to “Simple arithmetic pattern (saturating add)”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@template SAT_ADD(a, b, out)</span></span>
<span class="line"><span>  @scratch sum [widthof(a)+1];</span></span>
<span class="line"><span>  sum &lt;=z uadd(a, b);</span></span>
<span class="line"><span>  out &lt;= sum[widthof(a)] ? {widthof(a){1&#39;b1}} : sum[widthof(a)-1:0];</span></span>
<span class="line"><span>@endtemplate</span></span></code></pre></div><p>Usage:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ASYNCHRONOUS {</span></span>
<span class="line"><span>  @apply SAT_ADD(x, y, result);</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="multi-line-logic-clamping" tabindex="-1">Multi-line logic (clamping) <a class="header-anchor" href="#multi-line-logic-clamping" aria-label="Permalink to “Multi-line logic (clamping)”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@template CLAMP(val, lo, hi, out)</span></span>
<span class="line"><span>  IF (val &lt; lo) {</span></span>
<span class="line"><span>    out &lt;= lo;</span></span>
<span class="line"><span>  } ELIF (val &gt; hi) {</span></span>
<span class="line"><span>    out &lt;= hi;</span></span>
<span class="line"><span>  } ELSE {</span></span>
<span class="line"><span>    out &lt;= val;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>@endtemplate</span></span></code></pre></div><h3 id="scratch-wire-with-operations" tabindex="-1">Scratch wire with operations <a class="header-anchor" href="#scratch-wire-with-operations" aria-label="Permalink to “Scratch wire with operations”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@template XOR_THEN_SHIFT(a, b, out)</span></span>
<span class="line"><span>  @scratch t [widthof(a)];</span></span>
<span class="line"><span>  t &lt;= a ^ b;</span></span>
<span class="line"><span>  out &lt;= t &lt;&lt; 1;</span></span>
<span class="line"><span>@endtemplate</span></span></code></pre></div><h3 id="template-in-a-synchronous-block" tabindex="-1">Template in a SYNCHRONOUS block <a class="header-anchor" href="#template-in-a-synchronous-block" aria-label="Permalink to “Template in a SYNCHRONOUS block”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>SYNCHRONOUS(CLK=clk) {</span></span>
<span class="line"><span>  @apply CLAMP(counter, 16&#39;h0004, 16&#39;h0FFF, counter);</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Still subject to Exclusive Assignment analysis after expansion.</p><h3 id="unrolling-with-idx" tabindex="-1">Unrolling with IDX <a class="header-anchor" href="#unrolling-with-idx" aria-label="Permalink to “Unrolling with IDX”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@template grant(pbus_in, grant_reg)</span></span>
<span class="line"><span>  IF (pbus_in[IDX].REQ == 1&#39;b1) {</span></span>
<span class="line"><span>    grant_reg[IDX+1:0] &lt;= 1&#39;b1;</span></span>
<span class="line"><span>  } ELSE {</span></span>
<span class="line"><span>    grant_reg[IDX+1:0] &lt;= 1&#39;b0;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>@endtemplate</span></span></code></pre></div><p>Usage:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>SYNCHRONOUS(CLK=clk, RESET=reset, RESET_ACTIVE=High) {</span></span>
<span class="line"><span>  // Expand this template CONFIG.SOURCES times,</span></span>
<span class="line"><span>  // substituting IDX = 0..CONFIG.SOURCES-1</span></span>
<span class="line"><span>  @apply[CONFIG.SOURCES] grant(pbus, reg);</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="error-cases" tabindex="-1">Error Cases <a class="header-anchor" href="#error-cases" aria-label="Permalink to “Error Cases”">​</a></h2><h3 id="illegal-declaration-inside-template" tabindex="-1">Illegal declaration inside template <a class="header-anchor" href="#illegal-declaration-inside-template" aria-label="Permalink to “Illegal declaration inside template”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@template BAD(a, b)</span></span>
<span class="line"><span>  WIRE { t[8]; }  // ERROR: declarations not allowed in templates</span></span>
<span class="line"><span>@endtemplate</span></span></code></pre></div><h3 id="scratch-wire-used-outside-template" tabindex="-1">Scratch wire used outside template <a class="header-anchor" href="#scratch-wire-used-outside-template" aria-label="Permalink to “Scratch wire used outside template”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@scratch t [8];</span></span>
<span class="line"><span>x &lt;= t;  // ERROR: scratch t not visible here</span></span></code></pre></div><h3 id="illegal-nested-template" tabindex="-1">Illegal nested template <a class="header-anchor" href="#illegal-nested-template" aria-label="Permalink to “Illegal nested template”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@template A()</span></span>
<span class="line"><span>  @template B()  // ERROR: nested templates not allowed</span></span>
<span class="line"><span>  @endtemplate</span></span>
<span class="line"><span>@endtemplate</span></span></code></pre></div><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to “Rationale”">​</a></h2><h3 id="safety" tabindex="-1">Safety <a class="header-anchor" href="#safety" aria-label="Permalink to “Safety”">​</a></h3><ul><li>No new structural declarations except scratch wires</li><li>No storage</li><li>No clocks</li><li>No namespace pollution</li><li>No way to create implicit modules</li></ul><h3 id="power" tabindex="-1">Power <a class="header-anchor" href="#power" aria-label="Permalink to “Power”">​</a></h3><ul><li>Multi-line code reuse</li><li>Scratch wires enable non-trivial logic</li><li>Combinational logic patterns become reusable</li><li>Inline expansion ensures determinism and traceability</li><li>Works in both ASYNCHRONOUS and SYNCHRONOUS blocks</li></ul><h3 id="clarity" tabindex="-1">Clarity <a class="header-anchor" href="#clarity" aria-label="Permalink to “Clarity”">​</a></h3><ul><li>Templates are clearly not modules</li><li>No state</li><li>No driver surprises</li><li>Always visible in expanded form</li></ul>`,80)])])}const g=a(l,[["render",n]]);export{m as __pageData,g as default};
